"use strict";(self.webpackChunksysanalyst_kb=self.webpackChunksysanalyst_kb||[]).push([["88099"],{271(s){s.exports=JSON.parse('{"tag":{"label":"nmck","permalink":"/sysanalyst-kb.github.io/docs/tags/nmck","allTagsPath":"/sysanalyst-kb.github.io/docs/tags","count":1,"items":[{"id":"specialization/govtech-procurement","title":"\u0413\u043E\u0441\u0437\u0430\u043A\u0443\u043F\u043A\u0438 \u0432 IT (44-\u0424\u0417, 223-\u0424\u0417)","description":"44-\u0424\u0417 \u2014 \u0433\u043E\u0441\u0437\u0430\u043A\u0443\u043F\u043A\u0438 \u0434\u043B\u044F \u0431\u044E\u0434\u0436\u0435\u0442\u043D\u044B\u0445 \u0443\u0447\u0440\u0435\u0436\u0434\u0435\u043D\u0438\u0439 (\u0441\u0442\u0440\u043E\u0433\u0438\u0435 \u043F\u0440\u043E\u0446\u0435\u0434\u0443\u0440\u044B, \u0430\u0443\u043A\u0446\u0438\u043E\u043D\u044B, \u043A\u043E\u043D\u043A\u0443\u0440\u0441\u044B, \u043E\u0431\u044F\u0437\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0435 \u0422\u0417, \u0441\u0440\u043E\u043A\u0438 30-90 \u0434\u043D\u0435\u0439). 223-\u0424\u0417 \u2014 \u0434\u043B\u044F \u0433\u043E\u0441\u043A\u043E\u043C\u043F\u0430\u043D\u0438\u0439 (\u0433\u0438\u0431\u0447\u0435, \u0441\u0432\u043E\u0438 \u043F\u043E\u043B\u043E\u0436\u0435\u043D\u0438\u044F, 15-45 \u0434\u043D\u0435\u0439). \u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u043D\u0430 \u0441\u0442\u043E\u0440\u043E\u043D\u0435 \u0437\u0430\u043A\u0430\u0437\u0447\u0438\u043A\u0430 \u043F\u0438\u0448\u0435\u0442 \u0422\u0417, \u043E\u0431\u043E\u0441\u043D\u043E\u0432\u044B\u0432\u0430\u0435\u0442 \u041D\u041C\u0426\u041A, \u043F\u0440\u043E\u0432\u0435\u0440\u044F\u0435\u0442 \u0437\u0430\u044F\u0432\u043A\u0438. \u041D\u0430 \u0441\u0442\u043E\u0440\u043E\u043D\u0435 \u0438\u0441\u043F\u043E\u043B\u043D\u0438\u0442\u0435\u043B\u044F \u2014 \u0430\u043D\u0430\u043B\u0438\u0437\u0438\u0440\u0443\u0435\u0442 \u0422\u0417, \u043E\u0446\u0435\u043D\u0438\u0432\u0430\u0435\u0442 \u043E\u0431\u044A\u0451\u043C, \u0433\u043E\u0442\u043E\u0432\u0438\u0442 \u0442\u0435\u0445\u043F\u0440\u0435\u0434\u043B\u043E\u0436\u0435\u043D\u0438\u0435. \u0415\u0418\u0421 (zakupki.gov.ru) \u2014 \u0435\u0434\u0438\u043D\u044B\u0439 \u043F\u043E\u0440\u0442\u0430\u043B \u0437\u0430\u043A\u0443\u043F\u043E\u043A, \u043F\u0443\u0431\u043B\u0438\u043A\u0443\u044E\u0442\u0441\u044F \u0432\u0441\u0435 \u0442\u0435\u043D\u0434\u0435\u0440\u044B. \u0420\u044B\u043D\u043E\u043A \u0433\u043E\u0441\u0437\u0430\u043A\u0443\u043F\u043E\u043A IT \u0432 \u0420\u0424 \u2014 500+ \u043C\u043B\u0440\u0434 \u20BD/\u0433\u043E\u0434.","permalink":"/sysanalyst-kb.github.io/docs/specialization/govtech-procurement"}],"unlisted":false}}')}}]);